  1096в†’## 4.3 Run Assignment Optimizer
  1097в†’
  1098в†’### 4.3.1 Purpose
  1099в†’
  1100в†’Optimize daily train-to-route assignments for mileage balancing while respecting hard constraints (fitness, PM due, **unavailability**, **service demand**) and minimizing soft constraint penalties.
  1101в†’
  1102в†’### 4.3.2 Optimizer Service (TypeScript Wrapper)
  1103в†’
  1104в†’```typescript
  1105в†’interface OptimizerConfig {
  1106в†’  binaryPath: string;          // ./mms-optimizer
  1107в†’  maxSolveTimeSeconds: number; // 30
  1108в†’  numWorkers: number;          // 4
  1109в†’  timeoutMs: number;           // 60000
  1110в†’  fallbackEnabled: boolean;    // true
  1111в†’}
  1112в†’
  1113в†’class RunAssignmentOptimizer {
  1114в†’  private process: Subprocess | null = null;
  1115в†’  
  1116в†’  async optimize(input: OptimizerInput): Promise<OptimizerResult> {
  1117в†’    const startTime = Date.now();
  1118в†’    
  1119в†’    try {
  1120в†’      // Try C++ optimizer first
  1121в†’      const result = await this.runCppOptimizer(input);
  1122в†’      
  1123в†’      // Validate result
  1124в†’      if (result.status === 'INFEASIBLE' && this.config.fallbackEnabled) {
  1125в†’        this.logger.warn('C++ optimizer returned INFEASIBLE, using fallback');
  1126в†’        return await this.runFallbackOptimizer(input);
  1127в†’      }
  1128в†’      
  1129в†’      return result;
  1130в†’      
  1131в†’    } catch (error) {
  1132в†’      this.logger.error({ error }, 'C++ optimizer failed, using fallback');
  1133в†’      
  1134в†’      if (this.config.fallbackEnabled) {
  1135в†’        return await this.runFallbackOptimizer(input);
  1136в†’      }
  1137в†’      
  1138в†’      throw error;
  1139в†’    }
  1140в†’  }
  1141в†’  
  1142в†’  private async runCppOptimizer(input: OptimizerInput): Promise<OptimizerResult> {
  1143в†’    return new Promise((resolve, reject) => {
  1144в†’      const timeout = setTimeout(() => {
  1145в†’        this.process?.kill();
  1146в†’        reject(new Error('Optimizer timeout'));
  1147в†’      }, this.config.timeoutMs);
  1148в†’      
  1149в†’      this.process = Bun.spawn([this.config.binaryPath], {
  1150в†’        stdin: 'pipe',
  1151в†’        stdout: 'pipe',
  1152в†’        stderr: 'pipe'
  1153в†’      });
  1154в†’      
  1155в†’      // Write input
  1156в†’      const writer = this.process.stdin.getWriter();
  1157в†’      writer.write(new TextEncoder().encode(JSON.stringify(input) + '\n'));
  1158в†’      writer.close();
  1159в†’      
  1160в†’      // Read stdout (results)
  1161в†’      const results: any[] = [];
  1162в†’      const reader = this.process.stdout.getReader();
  1163в†’      const decoder = new TextDecoder();
  1164в†’      let buffer = '';
  1165в†’      
  1166в†’      const readStream = async () => {
  1167в†’        while (true) {
  1168в†’          const { done, value } = await reader.read();
  1169в†’          if (done) break;
  1170в†’          
  1171в†’          buffer += decoder.decode(value, { stream: true });
  1172в†’          const lines = buffer.split('\n');
  1173в†’          buffer = lines.pop() || '';
  1174в†’          
  1175в†’          for (const line of lines) {
  1176в†’            if (!line.trim()) continue;
  1177в†’            
  1178в†’            try {
  1179в†’              const msg = JSON.parse(line);
  1180в†’              
  1181в†’              if (msg.type === 'PROGRESS') {
  1182в†’                this.emitProgress(msg);
  1183в†’              } else if (msg.type === 'RESULT') {
  1184в†’                clearTimeout(timeout);
  1185в†’                resolve(this.mapResult(msg));
  1186в†’                return;
  1187в†’              }
  1188в†’            } catch (e) {
  1189в†’              this.logger.warn({ line }, 'Failed to parse optimizer output');
  1190в†’            }
  1191в†’          }
  1192в†’        }
  1193в†’      };
  1194в†’      
  1195в†’      // Read stderr (metrics/logs)
  1196в†’      this.readStderr(this.process.stderr);
  1197в†’      
  1198в†’      readStream().catch(reject);
  1199в†’      
  1200в†’      this.process.exited.then((code) => {
  1201в†’        clearTimeout(timeout);
  1202в†’        if (code !== 0 && results.length === 0) {
  1203в†’          reject(new Error(`Optimizer exited with code ${code}`));
  1204в†’        }
  1205в†’      });
  1206в†’    });
  1207в†’  }
  1208в†’  
  1209в†’  private async runFallbackOptimizer(input: OptimizerInput): Promise<OptimizerResult> {
  1210в†’    // TypeScript greedy fallback
  1211в†’    const assignments: Assignment[] = [];
  1212в†’    const unassigned: UnassignedTrain[] = [];
  1213в†’    const assignedTrainIds = new Set<string>();
  1214в†’    
  1215в†’    // Sort routes by priority (required trains desc)
  1216в†’    const sortedRoutes = [...input.routes].sort(
  1217в†’      (a, b) => b.required_trains - a.required_trains
  1218в†’    );
  1219в†’    
  1220в†’    // Sort trains by fitness and mileage balance
  1221в†’    const sortedTrains = [...input.trains]
  1222в†’      .filter(t => t.fitness_status === 'FIT')
  1223в†’      .sort((a, b) => {
  1224в†’        // Prioritize under-utilized trains
  1225в†’        const aBalance = a.current_mileage - a.target_mileage;
  1226в†’        const bBalance = b.current_mileage - b.target_mileage;
  1227в†’        return aBalance - bBalance;
  1228в†’      });
  1229в†’    
  1230в†’    for (const route of sortedRoutes) {
  1231в†’      let assigned = 0;
  1232в†’      
  1233в†’      for (const train of sortedTrains) {
  1234в†’        if (assigned >= route.required_trains) break;
  1235в†’        if (assignedTrainIds.has(train.id)) continue;
  1236в†’        
  1237в†’        // Check hard constraints
  1238в†’        const hardViolation = this.checkHardConstraints(train, route, input);
  1239в†’        if (hardViolation) {
  1240в†’          continue;
  1241в†’        }
  1242в†’        
  1243в†’        // Check fleet compatibility
  1244в†’        if (route.allowed_fleets.length > 0 && 
  1245в†’            !route.allowed_fleets.includes(train.fleet_id)) {
  1246в†’          continue;
  1247в†’        }
  1248в†’        
  1249в†’        // Assign
  1250в†’        assignments.push({
  1251в†’          train_id: train.id,
  1252в†’          route_id: route.id,
  1253в†’          score: this.calculateScore(train, route),
  1254в†’          explanation: [
  1255в†’            {
  1256в†’              constraint_type: 'SOFT',
  1257в†’              constraint_name: 'MILEAGE_BALANCE',
  1258в†’              impact: train.current_mileage - train.target_mileage,
  1259в†’              description: `Train is ${Math.abs(train.current_mileage - train.target_mileage)}km ${
  1260в†’                train.current_mileage < train.target_mileage ? 'under' : 'over'
  1261в†’              } target`
  1262в†’            }
  1263в†’          ]
  1264в†’        });
  1265в†’        
  1266в†’        assignedTrainIds.add(train.id);
  1267в†’        assigned++;
  1268в†’      }
  1269в†’      
  1270в†’      // Record shortfall
  1271в†’      if (assigned < route.required_trains) {
  1272в†’        unassigned.push({
  1273в†’          route_id: route.id,
  1274в†’          shortfall: route.required_trains - assigned,
  1275в†’          reason: 'Insufficient fit trains available'
  1276в†’        });
  1277в†’      }
  1278в†’    }
  1279в†’    
  1280в†’    // Record unassigned trains with reasons
  1281в†’    for (const train of input.trains) {
  1282в†’      if (assignedTrainIds.has(train.id)) continue;
  1283в†’      
  1284в†’      const reason = train.fitness_status !== 'FIT' 
  1285в†’        ? `Train is ${train.fitness_status}`
  1286в†’        : this.findBlockingConstraint(train, input);
  1287в†’      
  1288в†’      unassigned.push({
  1289в†’        train_id: train.id,
  1290в†’        reason,
  1291в†’        blocking_constraints: this.getBlockingConstraints(train, input)
  1292в†’      });
  1293в†’    }
  1294в†’    
  1295в†’    return {
  1296в†’      type: 'RESULT',
  1297в†’      request_id: input.request_id,
  1298в†’      status: 'FALLBACK',
  1299в†’      solve_time_ms: 0,
  1300в†’      assignments,
  1301в†’      unassigned,
  1302в†’      material_warnings: [],
  1303в†’      summary: {
  1304в†’        total_penalty: 1e6,  // High penalty for fallback
  1305в†’        trains_assigned: assignments.length,
  1306в†’        trains_unassigned: unassigned.length,
  1307в†’        soft_constraint_breakdown: {},
  1308в†’        material_blocks: 0
  1309в†’      }
  1310в†’    };
  1311в†’  }
  1312в†’  
  1313в†’  private checkHardConstraints(
  1314в†’    train: Train,
  1315в†’    route: Route,
  1316в†’    input: OptimizerInput
  1317в†’  ): string | null {
