  2465в†’    history: PMHistory[],
  2466в†’    currentMileage: number,
  2467в†’    currentDate: Date,
  2468в†’    dailyKm: number
  2469в†’  ): { date: Date; mileage: number; trigger: 'MILEAGE' | 'TIME' } {
  2470в†’    
  2471в†’    // 1. Find all PM types that SATISFY the target PM
  2472в†’    // (the target itself + any higher-level PM that includes target in satisfiesCodes)
  2473в†’    const satisfyingCodes = this.getSatisfyingCodes(targetRule.pmCode, allRules);
  2474в†’    
  2475в†’    // 2. Find the most recent PM that satisfies this requirement
  2476в†’    const lastSatisfying = history
  2477в†’      .filter(h => satisfyingCodes.includes(h.pmCode))
  2478в†’      .sort((a, b) => b.mileageAtCompletion - a.mileageAtCompletion)[0];
  2479в†’    
  2480в†’    // 3. Handle "Cold Start" - no PM history exists
  2481в†’    //    Assume train has been maintained on schedule since commissioning.
  2482в†’    //    Calculate which cycle we're currently in and when it started.
  2483в†’    let lastMileage: number;
  2484в†’    let lastDate: Date;
  2485в†’    
  2486в†’    if (lastSatisfying) {
  2487в†’      // Normal case: use actual history
  2488в†’      lastMileage = lastSatisfying.mileageAtCompletion;
  2489в†’      lastDate = new Date(lastSatisfying.completionDate);
  2490в†’    } else {
  2491в†’      // COLD START FIX: Create "virtual" last PM
  2492в†’      // Calculate how many complete cycles since commissioning
  2493в†’      const cyclesCompleted = Math.floor(currentMileage / targetRule.intervalKm);
  2494в†’      
  2495в†’      if (cyclesCompleted > 0) {
  2496в†’        // Assume last PM occurred at start of current cycle
  2497в†’        lastMileage = cyclesCompleted * targetRule.intervalKm;
  2498в†’        // Estimate when that mileage was reached
  2499в†’        const daysAgo = (currentMileage - lastMileage) / dailyKm;
  2500в†’        lastDate = addDays(currentDate, -daysAgo);
  2501в†’      } else {
  2502в†’        // Train hasn't completed first cycle yet - use commissioning as baseline
  2503в†’        lastMileage = 0;
  2504в†’        lastDate = train.commissioningDate;
  2505в†’      }
  2506в†’    }
  2507в†’    
  2508в†’    // 4. Calculate mileage-based due date
  2509в†’    const kmSinceLast = currentMileage - lastMileage;
  2510в†’    const kmRemaining = Math.max(0, targetRule.intervalKm - kmSinceLast);
  2511в†’    const daysUntilMileageDue = kmRemaining / dailyKm;
  2512в†’    const dateByMileage = addDays(currentDate, daysUntilMileageDue);
  2513в†’    const mileageAtDue = currentMileage + kmRemaining;
  2514в†’    
  2515в†’    // 5. Calculate time-based due date (if interval defined)
  2516в†’    let dateByTime: Date | null = null;
  2517в†’    if (targetRule.intervalMonths) {
  2518в†’      dateByTime = addMonths(lastDate, targetRule.intervalMonths);
  2519в†’    }
  2520в†’    
  2521в†’    // 6. Return whichever comes first (dual trigger)
  2522в†’    if (dateByTime && dateByTime < dateByMileage) {
  2523в†’      const daysUntilTime = differenceInDays(dateByTime, currentDate);
  2524в†’      const mileageAtTime = currentMileage + (Math.max(0, daysUntilTime) * dailyKm);
  2525в†’      return { date: dateByTime, mileage: mileageAtTime, trigger: 'TIME' };
  2526в†’    } else {
  2527в†’      return { date: dateByMileage, mileage: mileageAtDue, trigger: 'MILEAGE' };
  2528в†’    }
  2529в†’  }
  2530в†’  
  2531в†’  /**
  2532в†’   * Find all PM codes that satisfy a target PM code.
  2533в†’   * Returns the target itself plus any higher-level PMs that include it in satisfiesCodes.
  2534в†’   * 
  2535в†’   * Example: For C2, returns ['C2', 'C3', 'C4', 'OH'] because C3/C4/OH all satisfy C2.
  2536в†’   */
  2537в†’  private getSatisfyingCodes(targetCode: string, allRules: PMType[]): string[] {
  2538в†’    const result = [targetCode];
  2539в†’    
  2540в†’    for (const rule of allRules) {
  2541в†’      if (rule.satisfiesCodes?.includes(targetCode)) {
  2542в†’        result.push(rule.pmCode);
  2543в†’      }
  2544в†’    }
  2545в†’    
  2546в†’    return result;
  2547в†’  }
  2548в†’  
  2549в†’  /**
  2550в†’   * Calculate daily mileage rate for a train.
  2551в†’   * Uses recent velocity (between last 2 PMs) if available for accuracy,
  2552в†’   * falls back to lifetime average from commissioning date.
  2553в†’   */
  2554в†’  private calculateDailyUtilization(train: Train, history: PMHistory[]): number {
  2555в†’    // Filter valid entries (positive mileage)
  2556в†’    const validHistory = history
  2557в†’      .filter(h => h.mileageAtCompletion > 0)
  2558в†’      .sort((a, b) => new Date(b.completionDate).getTime() - new Date(a.completionDate).getTime());
  2559в†’    
  2560в†’    // Try: Recent velocity between last 2 PMs (most accurate)
  2561в†’    if (validHistory.length >= 2) {
  2562в†’      const recent = validHistory[0];
  2563в†’      const previous = validHistory[1];
  2564в†’      const daysBetween = differenceInDays(
  2565в†’        new Date(recent.completionDate),
  2566в†’        new Date(previous.completionDate)
  2567в†’      );
  2568в†’      const kmBetween = recent.mileageAtCompletion - previous.mileageAtCompletion;
  2569в†’      
  2570в†’      // Sanity checks: at least 14 days apart, positive mileage, reasonable rate
  2571в†’      if (daysBetween >= 14 && kmBetween > 0) {
  2572в†’        const rate = kmBetween / daysBetween;
  2573в†’        // Typical metro range: 50-500 km/day
  2574в†’        if (rate > 50 && rate < 500) {
  2575в†’          return rate;
  2576в†’        }
  2577в†’      }
  2578в†’    }
  2579в†’    
  2580в†’    // Fallback: Lifetime average from commissioning
  2581в†’    const daysSinceCommission = differenceInDays(new Date(), train.commissioningDate);
  2582в†’    if (daysSinceCommission > 0 && train.currentMileageKm > 0) {
  2583в†’      return train.currentMileageKm / daysSinceCommission;
  2584в†’    }
  2585в†’    
  2586в†’    // Last resort: Fleet typical value
  2587в†’    return 150;  // Conservative metro average
  2588в†’  }
  2589в†’  
  2590в†’  private async runGeneticAlgorithm(
  2591в†’    requirements: PMRequirement[],
  2592в†’    envelopes: ConstraintEnvelope[]
  2593в†’  ): Promise<StrategicAllocation[]> {
  2594в†’    // Initialize population
  2595в†’    let population = this.initializePopulation(requirements, envelopes);
  2596в†’    
  2597в†’    for (let gen = 0; gen < this.config.generations; gen++) {
  2598в†’      // Evaluate fitness
  2599в†’      const fitness = population.map(individual => 
  2600в†’        this.evaluateFitness(individual, envelopes)
  2601в†’      );
  2602в†’      
  2603в†’      // Selection
  2604в†’      const selected = this.tournamentSelection(population, fitness);
  2605в†’      
  2606в†’      // Crossover
  2607в†’      const offspring = this.crossover(selected);
  2608в†’      
  2609в†’      // Mutation
  2610в†’      const mutated = this.mutate(offspring, envelopes);
  2611в†’      
  2612в†’      // Elitism
  2613в†’      const elite = this.selectElite(population, fitness);
  2614в†’      
  2615в†’      // New population
  2616в†’      population = [...elite, ...mutated];
  2617в†’      
  2618в†’      // Progress
  2619в†’      if (gen % 50 === 0) {
  2620в†’        const bestFitness = Math.max(...fitness);
  2621в†’        this.emitProgress(gen, this.config.generations, bestFitness);
  2622в†’      }
  2623в†’    }
  2624в†’    
  2625в†’    // Return best individual
  2626в†’    const finalFitness = population.map(i => 
  2627в†’      this.evaluateFitness(i, envelopes)
  2628в†’    );
  2629в†’    const bestIndex = finalFitness.indexOf(Math.max(...finalFitness));
  2630в†’    
  2631в†’    return population[bestIndex];
  2632в†’  }
  2633в†’  
  2634в†’  private evaluateFitness(
  2635в†’    individual: StrategicAllocation[],
  2636в†’    envelopes: ConstraintEnvelope[]
  2637в†’  ): number {
  2638в†’    let fitness = 1000;  // Start with base score
  2639в†’    
  2640в†’    // Penalty for constraint envelope violations
  2641в†’    for (const envelope of envelopes) {
  2642в†’      const quarterAllocations = individual.filter(
  2643в†’        a => a.targetQuarter === this.quarterKey(envelope.period)
  2644в†’      );
  2645в†’      
  2646в†’      // Track capacity check
  2647в†’      const trackHours = this.sumByTrackType(quarterAllocations);
  2648в†’      for (const [trackType, hours] of Object.entries(trackHours)) {
  2649в†’        const available = envelope.track_capacity.find(
  2650в†’          t => t.track_type === trackType
  2651в†’        )?.available_slot_days || 0;
  2652в†’        
  2653в†’        if (hours > available * 8) {  // 8 hours per slot-day
  2654в†’          fitness -= (hours - available * 8) * 10;  // Heavy penalty
  2655в†’        }
  2656в†’      }
  2657в†’      
  2658в†’      // Labor capacity check
  2659в†’      const totalHours = quarterAllocations.reduce(
  2660в†’        (sum, a) => sum + a.estimatedHours, 0
  2661в†’      );
  2662в†’      const availableLabor = envelope.labor_capacity.reduce(
  2663в†’        (sum, l) => sum + l.available_hours, 0
  2664в†’      );
  2665в†’      
  2666в†’      if (totalHours > availableLabor) {
  2667в†’        fitness -= (totalHours - availableLabor) * 5;
  2668в†’      }
  2669в†’      
  2670в†’      // Material capacity check (soft)
  2671в†’      // ... similar logic
  2672в†’    }
  2673в†’    
  2674в†’    // Bonus for workload leveling
  2675в†’    const quarterHours = this.groupByQuarter(individual);
  2676в†’    const variance = this.calculateVariance(Object.values(quarterHours));
  2677в†’    fitness -= variance * 0.1;  // Prefer even distribution
  2678в†’    
  2679в†’    // Bonus for respecting compliance windows
  2680в†’    for (const allocation of individual) {
  2681в†’      const compliance = this.checkComplianceWindow(allocation);
  2682в†’      if (compliance.inWindow) {
  2683в†’        fitness += 5;
  2684в†’      } else if (compliance.early) {
  2685в†’        fitness -= 2;  // Small penalty for early
  2686в†’      } else {
  2687в†’        fitness -= 20;  // Large penalty for late
  2688в†’      }
  2689в†’    }
  2690в†’    
  2691в†’    return Math.max(0, fitness);
  2692в†’  }
  2693в†’  
  2694в†’  private async generateEnvelopes(): Promise<ConstraintEnvelope[]> {
  2695в†’    const envelopes: ConstraintEnvelope[] = [];
  2696в†’    const startDate = new Date();
  2697в†’    
  2698в†’    for (let q = 0; q < this.config.horizonYears * 4; q++) {
  2699в†’      const quarterStart = addMonths(startDate, q * 3);
  2700в†’      const quarterEnd = addMonths(quarterStart, 3);
  2701в†’      
  2702в†’      const envelope = await this.constraintAggregation.generateEnvelope(
  2703в†’        quarterStart,
  2704в†’        quarterEnd,
  2705в†’        await this.getAllDepotIds()
  2706в†’      );
  2707в†’      
  2708в†’      envelopes.push(envelope);
  2709в†’    }
  2710в†’    
  2711в†’    return envelopes;
  2712в†’  }
  2713в†’}
