  2717в†’
  2718в†’## 4.6 Man-hour Leveling Engine
  2719в†’
  2720в†’### 4.6.1 Purpose
  2721в†’
  2722в†’Project workforce requirements and generate adjustment recommendations to balance workload across time periods.
  2723в†’
  2724в†’### 4.6.2 Implementation
  2725в†’
  2726в†’```typescript
  2727в†’interface LevelingStrategy {
  2728в†’  type: 'DEFER_PM' | 'ADVANCE_PM' | 'ADD_OVERTIME' | 'CROSS_DEPOT' | 'ADD_CONTRACTOR';
  2729в†’  priority: number;
  2730в†’  maxHoursPerWeek: number;
  2731в†’  costMultiplier: number;
  2732в†’  riskLevel: 'NONE' | 'LOW' | 'MEDIUM' | 'HIGH';
  2733в†’}
  2734в†’
  2735в†’const LEVELING_STRATEGIES: LevelingStrategy[] = [
  2736в†’  { type: 'ADVANCE_PM', priority: 1, maxHoursPerWeek: 40, costMultiplier: 1.1, riskLevel: 'LOW' },
  2737в†’  { type: 'DEFER_PM', priority: 2, maxHoursPerWeek: 40, costMultiplier: 1.05, riskLevel: 'LOW' },
  2738в†’  { type: 'ADD_OVERTIME', priority: 3, maxHoursPerWeek: 80, costMultiplier: 1.5, riskLevel: 'NONE' },
  2739в†’  { type: 'CROSS_DEPOT', priority: 4, maxHoursPerWeek: 60, costMultiplier: 1.3, riskLevel: 'MEDIUM' },
  2740в†’  { type: 'ADD_CONTRACTOR', priority: 5, maxHoursPerWeek: 100, costMultiplier: 2.0, riskLevel: 'MEDIUM' },
  2741в†’];
  2742в†’
  2743в†’class ManHourLevelingEngine {
  2744в†’  private readonly TARGET_UTILIZATION = 0.85;
  2745в†’  private readonly MIN_UTILIZATION = 0.70;
  2746в†’  private readonly MAX_UTILIZATION = 1.00;
  2747в†’  
  2748в†’  async generateProjections(
  2749в†’    horizonWeeks: number = 12,
  2750в†’    depotIds?: string[]
  2751в†’  ): Promise<LevelingResult> {
  2752в†’    const runId = crypto.randomUUID();
  2753в†’    
  2754в†’    // 1. Calculate raw projections
  2755в†’    const rawProjections = await this.calculateRawProjections(
  2756в†’      horizonWeeks,
  2757в†’      depotIds
  2758в†’    );
  2759в†’    
  2760в†’    // 2. Identify imbalances
  2761в†’    const imbalances = this.identifyImbalances(rawProjections);
  2762в†’    
  2763в†’    // 3. Generate adjustments using multiple strategies
  2764в†’    const adjustments = await this.generateAdjustments(
  2765в†’      rawProjections,
  2766в†’      imbalances
  2767в†’    );
  2768в†’    
  2769в†’    // 4. Apply adjustments to get leveled projections
  2770в†’    const leveledProjections = this.applyAdjustments(
  2771в†’      rawProjections,
  2772в†’      adjustments
  2773в†’    );
  2774в†’    
  2775в†’    // 5. Calculate metrics
  2776в†’    const originalMetrics = this.calculateMetrics(rawProjections);
  2777в†’    const leveledMetrics = this.calculateMetrics(leveledProjections);
  2778в†’    
  2779в†’    // 6. Persist
  2780в†’    await this.persistProjections(runId, rawProjections, leveledProjections, adjustments);
  2781в†’    
  2782в†’    // 7. Broadcast update
  2783в†’    await this.websocketHub.broadcast('manhour:updated', {
  2784в†’      runId,
  2785в†’      summary: { originalMetrics, leveledMetrics }
  2786в†’    });
  2787в†’    
  2788в†’    return {
  2789в†’      projectionRunId: runId,
  2790в†’      generatedAt: new Date(),
  2791в†’      horizonWeeks,
  2792в†’      original: { projections: rawProjections, metrics: originalMetrics },
  2793в†’      leveled: { projections: leveledProjections, metrics: leveledMetrics },
  2794в†’      adjustments,
  2795в†’      improvement: {
  2796в†’        utilizationDelta: leveledMetrics.avgUtilization - originalMetrics.avgUtilization,
  2797в†’        overloadedWeeksReduced: originalMetrics.overloadedWeeks - leveledMetrics.overloadedWeeks,
  2798в†’        totalCostImpact: adjustments.reduce((sum, a) => sum + a.costImpact, 0)
  2799в†’      }
  2800в†’    };
  2801в†’  }
  2802в†’  
  2803в†’  private async generateAdjustments(
  2804в†’    projections: ManHourProjection[],
  2805в†’    imbalances: Imbalance[]
  2806в†’  ): Promise<ManHourAdjustment[]> {
  2807в†’    const adjustments: ManHourAdjustment[] = [];
  2808в†’    const byDepot = this.groupByDepot(projections);
  2809в†’    
  2810в†’    for (const [depotId, depotProjections] of byDepot) {
  2811в†’      const overloaded = depotProjections.filter(p => p.isOverloaded);
  2812в†’      const underutilized = depotProjections.filter(p => p.isUnderutilized);
  2813в†’      
  2814в†’      for (const overWeek of overloaded) {
  2815в†’        let remainingExcess = overWeek.required.total - overWeek.available.total;
  2816в†’        
  2817в†’        // Try each strategy in priority order
  2818в†’        for (const strategy of LEVELING_STRATEGIES) {
  2819в†’          if (remainingExcess <= 0) break;
  2820в†’          
  2821в†’          const adjustment = await this.tryStrategy(
  2822в†’            strategy,
  2823в†’            overWeek,
  2824в†’            underutilized,
  2825в†’            depotProjections,
  2826в†’            remainingExcess
  2827в†’          );
  2828в†’          
  2829в†’          if (adjustment) {
  2830в†’            adjustments.push(adjustment);
  2831в†’            remainingExcess -= adjustment.hoursAdjusted;
  2832в†’            
  2833в†’            // Update underutilized list if we used capacity
  2834в†’            if (adjustment.type === 'ADVANCE_PM' || adjustment.type === 'DEFER_PM') {
  2835в†’              this.updateUnderutilizedCapacity(underutilized, adjustment);
  2836в†’            }
  2837в†’          }
  2838в†’        }
  2839в†’        
  2840в†’        // If still overloaded, flag for manual review
  2841в†’        if (remainingExcess > 0) {
  2842в†’          adjustments.push({
  2843в†’            type: 'MANUAL_REVIEW',
  2844в†’            sourcePeriod: { start: overWeek.week, end: addDays(overWeek.week, 7) },
  2845в†’            hoursAdjusted: 0,
  2846в†’            affectedPMs: [],
  2847в†’            costImpact: 0,
  2848в†’            riskLevel: 'HIGH',
  2849в†’            reason: `Unable to resolve ${remainingExcess.toFixed(0)}h overload - requires manual intervention`
  2850в†’          });
  2851в†’        }
  2852в†’      }
  2853в†’    }
  2854в†’    
  2855в†’    return adjustments;
  2856в†’  }
  2857в†’  
  2858в†’  private async tryStrategy(
  2859в†’    strategy: LevelingStrategy,
  2860в†’    overloadedWeek: ManHourProjection,
  2861в†’    underutilizedWeeks: ManHourProjection[],
  2862в†’    allProjections: ManHourProjection[],
  2863в†’    excessHours: number
  2864в†’  ): Promise<ManHourAdjustment | null> {
  2865в†’    const maxHours = Math.min(strategy.maxHoursPerWeek, excessHours);
  2866в†’    
  2867в†’    switch (strategy.type) {
  2868в†’      case 'ADVANCE_PM':
  2869в†’      case 'DEFER_PM': {
  2870в†’        // Find candidate weeks
  2871в†’        const candidates = underutilizedWeeks
  2872в†’          .filter(w => {
  2873в†’            const weekDiff = differenceInWeeks(w.week, overloadedWeek.week);
  2874в†’            const direction = strategy.type === 'ADVANCE_PM' ? -1 : 1;
  2875в†’            return weekDiff * direction > 0 && Math.abs(weekDiff) <= 4;
  2876в†’          })
  2877в†’          .sort((a, b) => 
  2878в†’            Math.abs(differenceInWeeks(a.week, overloadedWeek.week)) -
  2879в†’            Math.abs(differenceInWeeks(b.week, overloadedWeek.week))
  2880в†’          );
  2881в†’        
  2882в†’        for (const candidate of candidates) {
  2883в†’          const availableCapacity = candidate.available.total - candidate.required.total;
  2884в†’          const shiftHours = Math.min(maxHours, availableCapacity * 0.8);
  2885в†’          
  2886в†’          if (shiftHours >= 8) {  // Minimum meaningful shift
  2887в†’            // Find PMs that can be shifted
  2888в†’            const shiftablePMs = await this.findShiftablePMs(
  2889в†’              overloadedWeek,
  2890в†’              candidate,
  2891в†’              shiftHours,
  2892в†’              strategy.type
  2893в†’            );
  2894в†’            
  2895в†’            if (shiftablePMs.length > 0) {
  2896в†’              const actualHours = shiftablePMs.reduce(
  2897в†’                (sum, pm) => sum + pm.estimatedHours, 0
  2898в†’              );
  2899в†’              
  2900в†’              return {
  2901в†’                type: strategy.type,
  2902в†’                sourcePeriod: { 
  2903в†’                  start: overloadedWeek.week, 
  2904в†’                  end: addDays(overloadedWeek.week, 7) 
  2905в†’                },
  2906в†’                targetPeriod: { 
  2907в†’                  start: candidate.week, 
  2908в†’                  end: addDays(candidate.week, 7) 
  2909в†’                },
  2910в†’                hoursAdjusted: actualHours,
  2911в†’                affectedPMs: shiftablePMs.map(pm => pm.id),
  2912в†’                costImpact: actualHours * this.getBaseRate() * (strategy.costMultiplier - 1),
  2913в†’                riskLevel: strategy.riskLevel,
  2914в†’                reason: `${strategy.type === 'DEFER_PM' ? 'Defer' : 'Advance'} ${actualHours.toFixed(0)}h from Week ${format(overloadedWeek.week, 'ww')} to Week ${format(candidate.week, 'ww')}`
  2915в†’              };
  2916в†’            }
  2917в†’          }
  2918в†’        }
  2919в†’        return null;
  2920в†’      }
  2921в†’      
  2922в†’      case 'ADD_OVERTIME': {
  2923в†’        const availableOvertime = overloadedWeek.available.overtime;
  2924в†’        const overtimeHours = Math.min(maxHours, availableOvertime);
  2925в†’        
  2926в†’        if (overtimeHours >= 4) {
  2927в†’          return {
  2928в†’            type: 'ADD_OVERTIME',
  2929в†’            sourcePeriod: { 
  2930в†’              start: overloadedWeek.week, 
  2931в†’              end: addDays(overloadedWeek.week, 7) 
  2932в†’            },
  2933в†’            targetPeriod: { 
  2934в†’              start: overloadedWeek.week, 
  2935в†’              end: addDays(overloadedWeek.week, 7) 
  2936в†’            },
  2937в†’            hoursAdjusted: overtimeHours,
  2938в†’            affectedPMs: [],
