  3463в†’  /**
  3464в†’   * Materialize a scenario (apply all deltas to get full state)
  3465в†’   */
  3466в†’  async materializeScenario(scenarioId: string): Promise<MaterializedScenario> {
  3467в†’    const scenario = await this.db.query.scenarios.findFirst({
  3468в†’      where: eq(scenarios.id, scenarioId)
  3469в†’    });
  3470в†’    
  3471в†’    if (!scenario) {
  3472в†’      throw new NotFoundError('Scenario not found');
  3473в†’    }
  3474в†’    
  3475в†’    // Get base state
  3476в†’    let basePMSchedule: PMScheduleRecord[];
  3477в†’    
  3478в†’    if (scenario.forkedFromBaselineId) {
  3479в†’      basePMSchedule = await this.db.query.baselinePmSchedule.findMany({
  3480в†’        where: eq(baselinePmSchedule.baselineId, scenario.forkedFromBaselineId)
  3481в†’      });
  3482в†’    } else if (scenario.forkedFromScenarioId) {
  3483в†’      // Recursive materialization
  3484в†’      const parentScenario = await this.materializeScenario(scenario.forkedFromScenarioId);
  3485в†’      basePMSchedule = parentScenario.pmSchedule;
  3486в†’    } else {
  3487в†’      // Fork from current production
  3488в†’      basePMSchedule = await this.db.query.pmSchedule.findMany({
  3489в†’        where: isNull(pmSchedule.scenarioId)
  3490в†’      });
  3491в†’    }
  3492в†’    
  3493в†’    // Get all deltas in order
  3494в†’    const deltas = await this.db.query.scenarioDeltas.findMany({
  3495в†’      where: eq(scenarioDeltas.scenarioId, scenarioId),
  3496в†’      orderBy: asc(scenarioDeltas.sequenceNum)
  3497в†’    });
  3498в†’    
  3499в†’    // Apply deltas
  3500в†’    const materializedPMSchedule = [...basePMSchedule];
  3501в†’    
  3502в†’    for (const delta of deltas) {
  3503в†’      switch (delta.deltaType) {
  3504в†’        case 'PM_MOVE': {
  3505в†’          const idx = materializedPMSchedule.findIndex(
  3506в†’            pm => pm.id === delta.entityId
  3507в†’          );
  3508в†’          if (idx >= 0) {
  3509в†’            materializedPMSchedule[idx] = {
  3510в†’              ...materializedPMSchedule[idx],
  3511в†’              ...delta.newValues
  3512в†’            };
  3513в†’          }
  3514в†’          break;
  3515в†’        }
  3516в†’        case 'PM_ADD': {
  3517в†’          materializedPMSchedule.push({
  3518в†’            id: delta.entityId,
  3519в†’            ...delta.newValues
  3520в†’          });
  3521в†’          break;
  3522в†’        }
  3523в†’        case 'PM_REMOVE': {
  3524в†’          const idx = materializedPMSchedule.findIndex(
  3525в†’            pm => pm.id === delta.entityId
  3526в†’          );
  3527в†’          if (idx >= 0) {
  3528в†’            materializedPMSchedule.splice(idx, 1);
  3529в†’          }
  3530в†’          break;
  3531в†’        }
  3532в†’      }
  3533в†’    }
  3534в†’    
  3535в†’    return {
  3536в†’      scenario,
  3537в†’      pmSchedule: materializedPMSchedule,
  3538в†’      deltasApplied: deltas.length
  3539в†’    };
  3540в†’  }
